export const agentStockCaseSourceReports = [
  "tmp/agent-companies100/report.json",
  "tmp/agent-latent-scaling/report.json",
  "tmp/agent-passives-carbon/report.json",
  "tmp/agent-robotics-signals/report.json",
  "tmp/agent-semis/report.json"
] as string[];

export function normalizeStockCaseKey(value: string | null | undefined) {
  return String(value ?? '').toUpperCase().replace(/[^A-Z0-9]/g, '');
}

export function getAgentStockCase(page: string, ticker?: string | null, company?: string | null) {
  const tickerKey = normalizeStockCaseKey(ticker);
  const companyKey = normalizeStockCaseKey(company);
  return (tickerKey ? agentStockCases[`${page}:${tickerKey}`] : undefined)
    ?? (companyKey ? agentStockCases[`${page}:${companyKey}`] : undefined)
    ?? (tickerKey ? agentStockCases[`global:${tickerKey}`] : undefined)
    ?? (companyKey ? agentStockCases[`global:${companyKey}`] : undefined);
}
